// // This module implements a two-to-one multiplexer where the output Y is selected based on the SEL input. When SEL is 0, Y outputs the value of A; when SEL is 1, Y outputs the value of B.
module top_module(
    Y   ,
    A   ,
    B   ,
    SEL ,
    VPWR,
    VGND,
    VPB ,
    VNB
);output Y   ;
    input  A   ;
    input  B   ;
    input  SEL ;
    input  VPWR;
    input  VGND;
    input  VPB ;
    input  VNB ;

    assign Y = SEL ? B : A;

endmodule
